"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const chapters=["Context","Decision","Outcome"];
export default function ChapterMarkerRail(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section className="w-full max-w-md rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><div className="flex gap-4"><nav aria-label="Reading chapters" className="w-20 shrink-0">{chapters.map((chapter,index)=><div key={chapter} aria-current={active===index?"step":undefined} className={active===index?"mb-3 flex items-center gap-2 text-xs font-black text-[#111]":"mb-3 flex items-center gap-2 text-xs font-bold text-[#4a4a4f]"}><motion.i animate={{scale:active===index&&!reduced?1.2:1}} className={active===index?"h-2.5 w-2.5 rounded-full bg-violet-400":"h-2.5 w-2.5 rounded-full bg-[#ececee]"}/>{index+1}</div>)}</nav><article tabIndex={0} aria-label="Scrollable chapter notes" onScroll={e=>{const target=e.currentTarget;setActive(Math.min(2,Math.floor(target.scrollTop/(target.scrollHeight-target.clientHeight||1)*3)));}} className="h-44 flex-1 overflow-y-auto rounded-2xl bg-[#f4f5f6] p-4 outline-offset-4 focus-visible:outline focus-visible:outline-2">{chapters.map((chapter,index)=><section key={chapter} className="mb-7"><h2 className="text-sm font-black text-[#111]">{chapter}</h2><p className="mt-1 text-sm leading-6 text-[#4a4a4f]">{index===0?"Set the shared context before choosing a direction.":index===1?"Document the tradeoff, owner, and next review point.":"Measure the outcome and leave one useful note."}</p></section>)}</article></div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Reading {chapters[active]}, chapter {active+1} of 3.</p></section>}
